import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.math.BigDecimal;
import javax.sql.DataSource;

public class BankTransactionProcessor {

    public enum TransactionType {
        DEBIT,
        CREDIT
    }

    public static boolean processTransaction(DataSource dataSource, int accountId, BigDecimal amount, TransactionType type) throws SQLException {
        Connection connection = null;
        PreparedStatement selectStmt = null;
        PreparedStatement updateStmt = null;
        boolean transactionSuccess = false;

        if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
            throw new SQLException("Invalid transaction amount: Amount must be positive.");
        }

        try {
            connection = dataSource.getConnection();
            connection.setAutoCommit(false);

            String selectSql = "SELECT balance FROM accounts WHERE account_id = ? FOR UPDATE";
            selectStmt = connection.prepareStatement(selectSql);
            selectStmt.setInt(1, accountId);

            ResultSet rs = selectStmt.executeQuery();
            if (!rs.next()) {
                throw new SQLException("Account with ID " + accountId + " not found.");
            }

            BigDecimal currentBalance = rs.getBigDecimal("balance");
            rs.close();

            BigDecimal newBalance;

            if (type == TransactionType.DEBIT) {
                if (currentBalance.compareTo(amount) < 0) {
                    throw new SQLException("Insufficient funds for account " + accountId + ". Current balance: " + currentBalance + ", Debit amount: " + amount);
                }
                newBalance = currentBalance.subtract(amount);
            } else if (type == TransactionType.CREDIT) {
                newBalance = currentBalance.add(amount);
            } else {
                throw new IllegalArgumentException("Unknown transaction type: " + type);
            }

            String updateSql = "UPDATE accounts SET balance = ? WHERE account_id = ?";
            updateStmt = connection.prepareStatement(updateSql);
            updateStmt.setBigDecimal(1, newBalance);
            updateStmt.setInt(2, accountId);

            int rowsAffected = updateStmt.executeUpdate();

            if (rowsAffected == 1) {
                connection.commit();
                transactionSuccess = true;
            } else {
                connection.rollback();
                throw new SQLException("Failed to update balance for account " + accountId + ". No rows affected.");
            }

        } catch (SQLException e) {
            if (connection != null) {
                try {
                    connection.rollback();
                } catch (SQLException ex) {
                    System.err.println("Rollback failed: " + ex.getMessage());
                }
            }
            throw e;
        } catch (IllegalArgumentException e) {
            if (connection != null) {
                try {
                    connection.rollback();
                } catch (SQLException ex) {
                    System.err.println("Rollback failed: " + ex.getMessage());
                }
            }
            throw new SQLException("Transaction validation error: " + e.getMessage(), e);
        } finally {
            if (selectStmt != null) {
                try {
                    selectStmt.close();
                } catch (SQLException e) { /* Log or ignore */ }
            }
            if (updateStmt != null) {
                try {
                    updateStmt.close();
                } catch (SQLException e) { /* Log or ignore */ }
            }
            if (connection != null) {
                try {
                    connection.setAutoCommit(true);
                    connection.close();
                } catch (SQLException e) { /* Log or ignore */ }
            }
        }
        return transactionSuccess;
    }
}